// ════════════════════════════════════════
// WF-11 政績列表 — 格式化 + 分頁
// Notion Simplify: OFF（走完整路徑）
// ════════════════════════════════════════

// 取得 query params
const query    = $('Webhook').first().json.query || {};
const page     = parseInt(query.page  ?? '1');
const limit    = parseInt(query.limit ?? '10');
const typeFilter = (query.type || '').trim();

// 原始 Notion items
const rawItems = $input.all();

// ── 格式化函式
function formatItem(item) {
  const props = item.json.properties || {};

  // 政績名稱
  const title = props['政績名稱']?.title?.[0]?.plain_text ?? '';

  // 政績類型
  const type = props['政績類型']?.select?.name ?? '';

  // 政績內容（取第一個 rich_text 塊；多塊時串接）
  const contentBlocks = props['政績內容']?.rich_text ?? [];
  const content = contentBlocks.map(b => b.plain_text).join('');

  // 成果日期
  const date = props['成果日期']?.date?.start ?? '';

  // 主圖片（優先 file URL，fallback external URL）
  const coverFiles = props['主圖片']?.files ?? [];
  const coverImage = coverFiles[0]?.file?.url
                  || coverFiles[0]?.external?.url
                  || null;

  // 附圖（多張）
  const imagesFiles = props['附圖']?.files ?? [];
  const images = imagesFiles.map(f => f?.file?.url || f?.external?.url).filter(Boolean);

  // 按讚數
  const likes = props['按讚數']?.number ?? 0;

  // 是否公開
  const isPublic = props['是否公開']?.checkbox ?? false;

  // 重要程度（置頂判斷）
  const importance = props['重要程度']?.select?.name ?? '一般';
  const isPinned   = importance === '重點';

  // 標籤
  const tags = (props['標籤']?.multi_select ?? []).map(t => t.name);

  // Notion Page ID
  const id = item.json.id;

  return { id, title, type, content, date, coverImage, images, likes, isPublic, isPinned, importance, tags };
}

// ── 格式化所有項目
let items = rawItems.map(formatItem);

// ── 類型篩選
if (typeFilter) {
  items = items.filter(i => i.type === typeFilter);
}

// ── 分頁
const total      = items.length;
const totalPages = Math.max(1, Math.ceil(total / limit));
const safePage   = Math.min(Math.max(page, 1), totalPages);
const start      = (safePage - 1) * limit;
const pageItems  = items.slice(start, start + limit);

// ── 輸出
return [
  {
    json: {
      success:    true,
      items:      pageItems,
      total,
      page:       safePage,
      totalPages,
    }
  }
];
